inline:<div id="header-root">
  <style>
    #header-root {
      background: #0A0A12;
      display: flex; flex-direction: column; align-items: center; justify-content: center;
      min-height: 400px; color: #00F2FF;
      font-family: 'Montserrat', sans-serif;
    }
    .c1-brand-container {
      position: relative; width: 100%; max-width: 800px; padding: 16px;
    }
    .c1-title {
      font-size: 3rem; letter-spacing: 0.3em; text-align: center;
      background: linear-gradient(90deg, #00F2FF, #FF00E5);
      -webkit-background-clip: text; -webkit-text-fill-color: transparent;
    }
    .c1-visual-anchor {
      height: 4px; width: 100px; background: #00F2FF;
      margin: 24px auto; transition: width 1s ease-out;
    }
    .c1-heading {
      text-align: center; font-family: 'JetBrains Mono', monospace;
      color: #FF00E5; font-size: 1rem;
    }
  </style>
  <div class="c1-brand-container">
    <h1 class="c1-title">DNA UNVEILED</h1>
    <div id="header-root-anchor" class="c1-visual-anchor"></div>
    <p class="c1-heading">Exploring the Blueprint of Life // Workshop 2026</p>
  </div>
  <script>
    window.c1_mount = () => {
      const anchor = document.getElementById('header-root-anchor');
      if (!window.matchMedia('(prefers-reduced-motion: reduce)').matches) {
        anchor.style.width = '300px';
      }
    };
    window.c1_destroy = () => {};
    window.c1_initializeHeaderAnimation = () => {};
  </script>
</div>
